/**
 * Unit tests for T032: Attribute Influence Stage
 *
 * TDD Approach: These tests MUST FAIL before implementation
 *
 * Tests validate:
 * - All role types (CORE, PRIMARY_BOOST, SECONDARY_BOOST, DISAMBIGUATOR, FILTER)
 * - Bonus calculations and score caps
 * - Role enforcement per SCORING_LOGIC.md
 * - Configuration validation
 */

import { describe, test, expect, beforeEach } from '@jest/globals';
import { EmailMessage, ProcessingConfig } from '../../src/types';
import { AttributeContext, AttributeRole } from '../../src/types/attribute-context';
import { CategoryConfiguration } from '../../src/types/category-configuration';
import { executeAttributeInfluence } from '../../src/stages/attribute-influence';
import { createClassificationSession, createClassificationResult } from '../../src/utils/initialization';

// Test-specific type for emails with additional properties
type TestEmailMessage = EmailMessage & {
  stage_results?: Record<string, unknown>;
};

describe('Attribute Influence Stage (T032)', () => {
  let mockEmail: EmailMessage;
  let mockContext: AttributeContext;
  let mockConfig: CategoryConfiguration;

  // Helper to set up test with session and result
  const setupTest = () => {
    const processingConfig: ProcessingConfig = {
      version: 1,
      taxonomy_notes: 'Test configuration',
      category_signals: {},
      settings: {
        initialization: {
          apply_hard_assertions: true,
          seed_category_scores: true,
        },
        rule_scoring: {
          use_lexical_patterns: true,
          apply_subtype_rules: true,
          bounded_aggregation: true,
        },
        attribute_processing: {
          detect_self_sent: true,
          resolve_domains: true,
          derive_context_flags: true,
        },
        attribute_influence: {
          apply_bonuses: true,
          apply_penalties: true,
          enforce_caps: true,
        },
        disambiguation: {
          pairwise_adjustments: true,
          confidence_gap_threshold: 0.15,
        },
        multi_label_selection: {
          max_labels: 3,
          min_secondary_confidence: 0.3,
          allowed_combinations: [],
        },
        ai_routing: {
          high_confidence_threshold: 0.8,
          ai_required_threshold: 0.4,
          skip_ai_conditions: [],
        },
      },
      confidence_thresholds: {
        high_confidence: 0.8,
        medium_confidence: 0.6,
        low_confidence: 0.2,
        ai_classification_required: 0.4,
        manual_review_required: 0.2,
        secondary_label_min_gap: 0.1,
      },
      multi_label_policy: {
        max_top_level_labels: 3,
        min_confidence_for_additional: 0.3,
        min_delta_primary_secondary: 0.1,
        allow_financial_actionable_copresence: true,
      },
      domain_signal_overrides: {},
      domain_signal_resolution: {
        mode: 'runtime_resolved',
        source: 'config/domain-sources.json',
        notes: 'Test configuration',
      },
      top_level_categories: {},
      attributes: {
        schema: {},
        detectors: [],
        derived: {},
        attribute_bonus_map: {},
      },
      attribute_relevance: {},
      ai_prompts: {
        feature_extraction: {
          system_prompt: ['Extract features'],
          user_prompt: ['Analyze email'],
        },
        final_classification: {
          system_prompt: ['Classify email'],
          user_prompt: ['Determine category'],
        },
      },
      feature_extraction_schema: {
        type: 'object',
        properties: {},
        required: [],
      },
    };

    const session = createClassificationSession(processingConfig, 'sequential', 1);
    const result = createClassificationResult(mockEmail.id, session.id, 0);

    // Copy detection metadata from mockContext to result.attributeContext
    result.attributeContext.detectionMetadata = { ...mockContext.detectionMetadata };
    result.attributeContext.emailId = mockEmail.id;
    result.attributeContext.urgency = mockContext.urgency || 'low';
    result.attributeContext.domains = [...(mockContext.domains || [])];
    result.attributeContext.structuralPatterns = [...(mockContext.structuralPatterns || [])];
    result.attributeContext.temporalSignals = [...(mockContext.temporalSignals || [])];

    return { session, result };
  };

  beforeEach(() => {
    // Setup test email
    mockEmail = {
      id: 'test-email-123',
      threadId: 'thread-456',
      gmailLabels: ['INBOX'],
      payload: {
        mimeType: 'text/plain',
        headers: [
          { name: 'From', value: 'test@example.com' },
          { name: 'Subject', value: 'Test Email' },
        ],
        body: { data: 'VGVzdCBlbWFpbCBib2R5' },
      },
      bodyPlain: 'Test email body',
      bodyHtml: '<p>Test email body</p>',
      subject: 'Test Email',
      from: {
        email: 'test@example.com',
        raw: 'test@example.com',
      },
      to: [
        {
          email: 'recipient@example.com',
          raw: 'recipient@example.com',
        },
      ],
      date: new Date('2024-01-01T10:00:00Z'),
      snippet: 'Test email body',
      isProcessed: false,
      processingPriority: 1,
    };

    // Setup attribute context with detected attributes
    mockContext = {
      emailId: 'test-email-123',
      urgency: 'medium',
      domains: ['financial.com'],
      structuralPatterns: ['invoice_pattern'],
      temporalSignals: ['end_of_month'],
      detectionMetadata: {
        financial_domain: {
          detectedAt: new Date(),
          detectionMethod: 'domain_lookup',
          confidence: 0.95,
          parallelProcessed: false,
          dependencies: [],
          sourceField: 'from.address',
          matchedValue: 'financial.com',
          detectorConfig: {
            field: 'from.address',
            operation: 'domain_extract',
            values: ['financial.com'],
            weight: 1.0,
            cacheEnabled: true,
            parallelSafe: true,
          },
          detectionTimeMs: 5,
          cacheUsed: false,
          retryCount: 0,
        },
      },
      influenceApplications: [],
      derivedAttributes: {},
      attributeRelationships: [],
    };

    // Setup category configuration with attribute relevance matrix
    mockConfig = {
      version: '1.0',
      lastModified: new Date('2024-01-01'),
      hash: 'test-hash',
      schemaVersion: '1.0',
      validationPassed: true,
      validationErrors: [],
      compiledRules: [],
      attributeMatrix: {},
      processing_config: {
        version: 1,
        taxonomy_notes: 'Test configuration',
        category_signals: {},
        settings: {
          initialization: {
            apply_hard_assertions: true,
            seed_category_scores: true,
          },
          rule_scoring: {
            use_lexical_patterns: true,
            apply_subtype_rules: true,
            bounded_aggregation: true,
          },
          attribute_processing: {
            detect_self_sent: true,
            resolve_domains: true,
            derive_context_flags: true,
          },
          attribute_influence: {
            apply_bonuses: true,
            apply_penalties: true,
            enforce_caps: true,
          },
          disambiguation: {
            pairwise_adjustments: true,
            confidence_gap_threshold: 0.15,
          },
          multi_label_selection: {
            max_labels: 3,
            min_secondary_confidence: 0.3,
            allowed_combinations: [],
          },
          ai_routing: {
            high_confidence_threshold: 0.8,
            ai_required_threshold: 0.4,
            skip_ai_conditions: [],
          },
        },
        confidence_thresholds: {
          high_confidence: 0.8,
          medium_confidence: 0.6,
          low_confidence: 0.2,
          ai_classification_required: 0.4,
          manual_review_required: 0.2,
          secondary_label_min_gap: 0.1,
        },
        multi_label_policy: {
          max_top_level_labels: 3,
          min_confidence_for_additional: 0.3,
          min_delta_primary_secondary: 0.1,
          allow_financial_actionable_copresence: true,
        },
        domain_signal_overrides: {},
        domain_signal_resolution: {
          mode: 'runtime_resolved',
          source: 'config/domain-sources.json',
          notes: 'Test configuration',
        },
        top_level_categories: {
          FINANCIAL: {
            description: 'Financial emails',
            subtypes: {
              BILLING: {
                description: 'Billing-related emails',
                rule_based_classification: {
                  high_confidence: [],
                  medium_confidence: [],
                  low_confidence: [],
                },
              },
            },
            ai_final_classification: {
              category_description: 'Financial content',
              decision_criteria: ['financial keywords'],
            },
          },
          PERSONAL: {
            description: 'Personal emails',
            subtypes: {
              FAMILY: {
                description: 'Family-related emails',
                rule_based_classification: {
                  high_confidence: [],
                  medium_confidence: [],
                  low_confidence: [],
                },
              },
            },
            ai_final_classification: {
              category_description: 'Personal content',
              decision_criteria: ['personal keywords'],
            },
          },
        },
        attributes: {
          schema: {},
          detectors: [],
          derived: {},
          attribute_bonus_map: {
            financial_domain: {
              FINANCIAL: 25,
              PERSONAL: -20,
            },
            invoice_pattern: {
              FINANCIAL: 15,
            },
            end_of_month: {
              FINANCIAL: 8,
            },
            urgent_indicator: {
              FINANCIAL: 5,
            },
            priority_flag: {
              FINANCIAL: 5,
            },
            billing_keyword: {
              FINANCIAL: 15,
            },
            business_hours: {
              FINANCIAL: 8,
            },
            business_language: {
              PERSONAL: -20,
            },
          },
        },
        // Attribute relevance matrix - key for this stage
        attribute_relevance: {
          _roles_legend: {
            CORE: 'Essential attributes that define the category',
            PRIMARY_BOOST: 'Strong positive indicators for the category',
            SECONDARY_BOOST: 'Moderate positive indicators',
            DISAMBIGUATOR: 'Helps choose between similar categories',
            FILTER: 'Rules out inappropriate categories',
            STRUCTURAL: 'Email structure and format indicators',
            DERIVED_LINK: 'Links to derived attribute calculations',
            NEUTRAL: 'No impact on category scoring',
          },
          FINANCIAL: {
            category_roles: {
              financial_domain: 'CORE',
              invoice_pattern: 'PRIMARY_BOOST',
              end_of_month: 'SECONDARY_BOOST',
              urgent_indicator: 'DISAMBIGUATOR',
            },
            subtypes: {
              BILLING: {
                roles: {
                  financial_domain: 'CORE',
                  invoice_pattern: 'CORE',
                  end_of_month: 'PRIMARY_BOOST',
                },
              },
            },
          },
          PERSONAL: {
            category_roles: {
              family_domain: 'CORE',
              personal_greeting: 'PRIMARY_BOOST',
              financial_domain: 'FILTER', // Filters out financial content
            },
            subtypes: {
              FAMILY: {
                roles: {
                  family_domain: 'CORE',
                  personal_greeting: 'CORE',
                },
              },
            },
          },
        },
        ai_prompts: {
          feature_extraction: {
            system_prompt: ['Extract features'],
            user_prompt: ['Analyze email'],
          },
          final_classification: {
            system_prompt: ['Classify email'],
            user_prompt: ['Determine category'],
          },
        },
        feature_extraction_schema: {
          type: 'object',
          properties: {},
          required: [],
        },
      },
    };
  });

  describe('Core Role Processing', () => {
    test('should apply CORE role bonuses correctly', () => {
      // Setup test with session and result
      const { session, result } = setupTest();
      result.emailId = mockEmail.id;

      // Execute stage (void return, mutates result)
      executeAttributeInfluence(mockEmail, session, result, mockConfig);

      // CORE attributes should get maximum bonus (25 points)
      expect(result.attributeContext.influenceApplications).toContainEqual(
        expect.objectContaining({
          targetCategory: 'FINANCIAL',
          attributeUsed: 'financial_domain',
          roleType: 'CORE',
          scoreImpact: 25,
        })
      );
    });

    test('should enforce CORE role caps', () => {
      // Multiple CORE attributes should be capped at 50 total
      mockContext.detectionMetadata.invoice_pattern = {
        detectedAt: new Date(),
        detectionMethod: 'pattern',
        confidence: 0.9,
        parallelProcessed: false,
        dependencies: [],
        sourceField: 'body',
        matchedValue: 'invoice',
        detectorConfig: {
          field: 'body',
          operation: 'pattern_match',
          values: ['invoice'],
          weight: 1.0,
          cacheEnabled: true,
          parallelSafe: true,
        },
        detectionTimeMs: 3,
        cacheUsed: false,
        retryCount: 0,
      };

      const { session, result } = setupTest();
      result.emailId = mockEmail.id;
      executeAttributeInfluence(mockEmail, session, result, mockConfig);

      // Filter by category-level (FINANCIAL) vs subtype-level (FINANCIAL.BILLING)
      const categoryLevelCores = result.attributeContext.influenceApplications.filter(
        (app) => app.targetCategory === 'FINANCIAL' && app.roleType === 'CORE'
      );
      const billingSubtypeCores = result.attributeContext.influenceApplications.filter(
        (app) => app.targetCategory === 'FINANCIAL.BILLING' && app.roleType === 'CORE'
      );

      const categoryLevelTotal = categoryLevelCores.reduce((sum, app) => sum + app.scoreImpact, 0);
      const billingSubtypeTotal = billingSubtypeCores.reduce((sum, app) => sum + app.scoreImpact, 0);

      // Each group should be capped at 50
      expect(categoryLevelTotal).toBeLessThanOrEqual(50);
      expect(billingSubtypeTotal).toBeLessThanOrEqual(50);
    });
  });

  describe('PRIMARY_BOOST Role Processing', () => {
    test('should apply PRIMARY_BOOST bonuses correctly', () => {
      mockContext.detectionMetadata.invoice_pattern = {
        detectedAt: new Date(),
        detectionMethod: 'pattern',
        confidence: 0.8,
        parallelProcessed: false,
        dependencies: [],
        sourceField: 'body',
        matchedValue: 'invoice',
        detectorConfig: {
          field: 'body',
          operation: 'pattern_match',
          values: ['invoice'],
          weight: 1.0,
          cacheEnabled: true,
          parallelSafe: true,
        },
        detectionTimeMs: 3,
        cacheUsed: false,
        retryCount: 0,
      };

      const { session, result } = setupTest();
      result.emailId = mockEmail.id;
      executeAttributeInfluence(mockEmail, session, result, mockConfig);

      expect(result.attributeContext.influenceApplications).toContainEqual(
        expect.objectContaining({
          targetCategory: 'FINANCIAL',
          attributeUsed: 'invoice_pattern',
          roleType: 'PRIMARY_BOOST',
          scoreImpact: 15,
        })
      );
    });

    test('should enforce PRIMARY_BOOST caps at 30 points', () => {
      // Add multiple PRIMARY_BOOST attributes
      mockContext.detectionMetadata.invoice_pattern = {
        detectedAt: new Date(),
        detectionMethod: 'pattern',
        confidence: 0.8,
        parallelProcessed: false,
        dependencies: [],
        sourceField: 'body',
        matchedValue: 'invoice',
        detectorConfig: {
          field: 'body',
          operation: 'pattern_match',
          values: ['invoice'],
          weight: 1.0,
          cacheEnabled: true,
          parallelSafe: true,
        },
        detectionTimeMs: 3,
        cacheUsed: false,
        retryCount: 0,
      };
      mockContext.detectionMetadata.billing_keyword = {
        detectedAt: new Date(),
        detectionMethod: 'pattern',
        confidence: 0.7,
        parallelProcessed: false,
        dependencies: [],
        sourceField: 'body',
        matchedValue: 'billing',
        detectorConfig: {
          field: 'body',
          operation: 'keyword_match',
          values: ['billing'],
          weight: 1.0,
          cacheEnabled: true,
          parallelSafe: true,
        },
        detectionTimeMs: 2,
        cacheUsed: false,
        retryCount: 0,
      };

      // Configure additional PRIMARY_BOOST attribute
      if ('category_roles' in mockConfig.processing_config.attribute_relevance.FINANCIAL) {
        mockConfig.processing_config.attribute_relevance.FINANCIAL.category_roles.billing_keyword = 'PRIMARY_BOOST';
      }

      const { session, result } = setupTest();
      result.emailId = mockEmail.id;
      executeAttributeInfluence(mockEmail, session, result, mockConfig);

      const primaryBoostInfluences = result.attributeContext.influenceApplications.filter(
        (app) => app.targetCategory === 'FINANCIAL' && app.roleType === 'PRIMARY_BOOST'
      );

      const totalPrimaryBonus = primaryBoostInfluences.reduce((sum, app) => sum + app.scoreImpact, 0);
      expect(totalPrimaryBonus).toBeLessThanOrEqual(30);
    });
  });

  describe('SECONDARY_BOOST Role Processing', () => {
    test('should apply SECONDARY_BOOST bonuses correctly', () => {
      mockContext.detectionMetadata.end_of_month = {
        detectedAt: new Date(),
        detectionMethod: 'derived',
        confidence: 0.6,
        parallelProcessed: false,
        dependencies: [],
        sourceField: 'date',
        matchedValue: 'end_of_month',
        detectorConfig: {
          field: 'date',
          operation: 'temporal_analysis',
          values: ['end_of_month'],
          weight: 1.0,
          cacheEnabled: true,
          parallelSafe: true,
        },
        detectionTimeMs: 1,
        cacheUsed: false,
        retryCount: 0,
      };

      const { session, result } = setupTest();
      result.emailId = mockEmail.id;
      executeAttributeInfluence(mockEmail, session, result, mockConfig);

      expect(result.attributeContext.influenceApplications).toContainEqual(
        expect.objectContaining({
          targetCategory: 'FINANCIAL',
          attributeUsed: 'end_of_month',
          roleType: 'SECONDARY_BOOST',
          scoreImpact: 8,
        })
      );
    });

    test('should enforce SECONDARY_BOOST caps at 16 points', () => {
      // Add multiple SECONDARY_BOOST attributes
      mockContext.detectionMetadata.end_of_month = {
        detectedAt: new Date(),
        detectionMethod: 'derived',
        confidence: 0.6,
        parallelProcessed: false,
        dependencies: [],
        sourceField: 'date',
        matchedValue: 'end_of_month',
        detectorConfig: {
          field: 'date',
          operation: 'temporal_analysis',
          values: ['end_of_month'],
          weight: 1.0,
          cacheEnabled: true,
          parallelSafe: true,
        },
        detectionTimeMs: 1,
        cacheUsed: false,
        retryCount: 0,
      };
      mockContext.detectionMetadata.business_hours = {
        detectedAt: new Date(),
        detectionMethod: 'derived',
        confidence: 0.5,
        parallelProcessed: false,
        dependencies: [],
        sourceField: 'date',
        matchedValue: 'business_hours',
        detectorConfig: {
          field: 'date',
          operation: 'temporal_analysis',
          values: ['business_hours'],
          weight: 1.0,
          cacheEnabled: true,
          parallelSafe: true,
        },
        detectionTimeMs: 1,
        cacheUsed: false,
        retryCount: 0,
      };

      // Configure additional SECONDARY_BOOST attribute
      if ('category_roles' in mockConfig.processing_config.attribute_relevance.FINANCIAL) {
        mockConfig.processing_config.attribute_relevance.FINANCIAL.category_roles.business_hours = 'SECONDARY_BOOST';
      }

      const { session, result } = setupTest();
      result.emailId = mockEmail.id;
      executeAttributeInfluence(mockEmail, session, result, mockConfig);

      const secondaryBoostInfluences = result.attributeContext.influenceApplications.filter(
        (app) => app.targetCategory === 'FINANCIAL' && app.roleType === 'SECONDARY_BOOST'
      );

      const totalSecondaryBonus = secondaryBoostInfluences.reduce((sum, app) => sum + app.scoreImpact, 0);
      expect(totalSecondaryBonus).toBeLessThanOrEqual(16);
    });
  });

  describe('DISAMBIGUATOR Role Processing', () => {
    test('should apply DISAMBIGUATOR bonuses for conflict resolution', () => {
      mockContext.detectionMetadata.urgent_indicator = {
        detectedAt: new Date(),
        detectionMethod: 'pattern',
        confidence: 0.7,
        parallelProcessed: false,
        dependencies: [],
        sourceField: 'subject',
        matchedValue: 'urgent',
        detectorConfig: {
          field: 'subject',
          operation: 'keyword_analysis',
          values: ['urgent', 'ASAP'],
          weight: 1.0,
          cacheEnabled: true,
          parallelSafe: true,
        },
        detectionTimeMs: 2,
        cacheUsed: false,
        retryCount: 0,
      };

      const { session, result } = setupTest();
      result.emailId = mockEmail.id;
      executeAttributeInfluence(mockEmail, session, result, mockConfig);

      expect(result.attributeContext.influenceApplications).toContainEqual(
        expect.objectContaining({
          targetCategory: 'FINANCIAL',
          attributeUsed: 'urgent_indicator',
          roleType: 'DISAMBIGUATOR',
          scoreImpact: 5,
        })
      );
    });

    test('should enforce DISAMBIGUATOR caps at 10 points', () => {
      // Add multiple DISAMBIGUATOR attributes
      mockContext.detectionMetadata.urgent_indicator = {
        detectedAt: new Date(),
        detectionMethod: 'pattern',
        confidence: 0.7,
        parallelProcessed: false,
        dependencies: [],
        sourceField: 'subject',
        matchedValue: 'urgent',
        detectorConfig: {
          field: 'subject',
          operation: 'keyword_analysis',
          values: ['urgent', 'ASAP'],
          weight: 1.0,
          cacheEnabled: true,
          parallelSafe: true,
        },
        detectionTimeMs: 2,
        cacheUsed: false,
        retryCount: 0,
      };
      mockContext.detectionMetadata.priority_flag = {
        detectedAt: new Date(),
        detectionMethod: 'pattern',
        confidence: 0.6,
        parallelProcessed: false,
        dependencies: [],
        sourceField: 'headers',
        matchedValue: 'priority',
        detectorConfig: {
          field: 'headers',
          operation: 'header_analysis',
          values: ['priority', 'importance'],
          weight: 1.0,
          cacheEnabled: true,
          parallelSafe: true,
        },
        detectionTimeMs: 1,
        cacheUsed: false,
        retryCount: 0,
      };

      // Configure additional DISAMBIGUATOR attribute
      if ('category_roles' in mockConfig.processing_config.attribute_relevance.FINANCIAL) {
        mockConfig.processing_config.attribute_relevance.FINANCIAL.category_roles.priority_flag = 'DISAMBIGUATOR';
      }

      const { session, result } = setupTest();
      result.emailId = mockEmail.id;
      executeAttributeInfluence(mockEmail, session, result, mockConfig);

      const disambiguatorInfluences = result.attributeContext.influenceApplications.filter(
        (app) => app.targetCategory === 'FINANCIAL' && app.roleType === 'DISAMBIGUATOR'
      );

      const totalDisambiguatorBonus = disambiguatorInfluences.reduce((sum, app) => sum + app.scoreImpact, 0);
      expect(totalDisambiguatorBonus).toBeLessThanOrEqual(10);
    });
  });

  describe('FILTER Role Processing', () => {
    test('should apply negative bonuses for FILTER attributes', () => {
      // PERSONAL category has financial_domain as FILTER
      mockContext.detectionMetadata.financial_domain = {
        detectedAt: new Date(),
        detectionMethod: 'domain_lookup',
        confidence: 0.9,
        parallelProcessed: false,
        dependencies: [],
        sourceField: 'from.address',
        matchedValue: 'financial.com',
        detectorConfig: {
          field: 'from.address',
          operation: 'domain_extract',
          values: ['financial.com'],
          weight: 1.0,
          cacheEnabled: true,
          parallelSafe: true,
        },
        detectionTimeMs: 5,
        cacheUsed: false,
        retryCount: 0,
      };

      const { session, result } = setupTest();
      result.emailId = mockEmail.id;
      executeAttributeInfluence(mockEmail, session, result, mockConfig);

      // Should filter out PERSONAL category with negative bonus
      expect(result.attributeContext.influenceApplications).toContainEqual(
        expect.objectContaining({
          targetCategory: 'PERSONAL',
          attributeUsed: 'financial_domain',
          roleType: 'FILTER',
          scoreImpact: -20, // Negative bonus
        })
      );
    });

    test('should enforce FILTER caps at -40 points', () => {
      // Add multiple FILTER attributes for PERSONAL category
      mockContext.detectionMetadata.financial_domain = {
        detectedAt: new Date(),
        detectionMethod: 'domain_lookup',
        confidence: 0.9,
        parallelProcessed: false,
        dependencies: [],
        sourceField: 'from.address',
        matchedValue: 'financial.com',
        detectorConfig: {
          field: 'from.address',
          operation: 'domain_extract',
          values: ['financial.com'],
          weight: 1.0,
          cacheEnabled: true,
          parallelSafe: true,
        },
        detectionTimeMs: 5,
        cacheUsed: false,
        retryCount: 0,
      };
      mockContext.detectionMetadata.business_language = {
        detectedAt: new Date(),
        detectionMethod: 'ai',
        confidence: 0.8,
        parallelProcessed: false,
        dependencies: [],
        sourceField: 'body',
        matchedValue: 'business',
        detectorConfig: {
          field: 'body',
          operation: 'nlp_analysis',
          values: ['business', 'corporate'],
          weight: 1.0,
          cacheEnabled: true,
          parallelSafe: true,
        },
        detectionTimeMs: 10,
        cacheUsed: false,
        retryCount: 0,
      };

      // Configure additional FILTER attribute
      if ('category_roles' in mockConfig.processing_config.attribute_relevance.PERSONAL) {
        mockConfig.processing_config.attribute_relevance.PERSONAL.category_roles.business_language = 'FILTER';
      }

      const { session, result } = setupTest();
      result.emailId = mockEmail.id;
      executeAttributeInfluence(mockEmail, session, result, mockConfig);

      const filterInfluences = result.attributeContext.influenceApplications.filter(
        (app) => app.targetCategory === 'PERSONAL' && app.roleType === 'FILTER'
      );

      const totalFilterPenalty = filterInfluences.reduce((sum, app) => sum + app.scoreImpact, 0);
      expect(totalFilterPenalty).toBeGreaterThanOrEqual(-40); // More negative than -40 not allowed
    });
  });

  describe('Subtype Role Processing', () => {
    test('should apply subtype-specific role bonuses', () => {
      // BILLING subtype has invoice_pattern as CORE
      mockContext.detectionMetadata.invoice_pattern = {
        detectedAt: new Date(),
        detectionMethod: 'pattern',
        confidence: 0.9,
        parallelProcessed: false,
        dependencies: [],
        sourceField: 'body',
        matchedValue: 'invoice',
        detectorConfig: {
          field: 'body',
          operation: 'pattern_match',
          values: ['invoice'],
          weight: 1.0,
          cacheEnabled: true,
          parallelSafe: true,
        },
        detectionTimeMs: 3,
        cacheUsed: false,
        retryCount: 0,
      };

      const { session, result } = setupTest();
      result.emailId = mockEmail.id;
      executeAttributeInfluence(mockEmail, session, result, mockConfig);

      // Should apply subtype-specific bonus for FINANCIAL.BILLING
      expect(result.attributeContext.influenceApplications).toContainEqual(
        expect.objectContaining({
          targetCategory: 'FINANCIAL.BILLING',
          attributeUsed: 'invoice_pattern',
          roleType: 'CORE',
          scoreImpact: 25,
        })
      );
    });

    test('should handle category vs subtype role conflicts', () => {
      // end_of_month is SECONDARY_BOOST for category but PRIMARY_BOOST for BILLING subtype
      mockContext.detectionMetadata.end_of_month = {
        detectedAt: new Date(),
        detectionMethod: 'derived',
        confidence: 0.7,
        parallelProcessed: false,
        dependencies: [],
        sourceField: 'date',
        matchedValue: 'end_of_month',
        detectorConfig: {
          field: 'date',
          operation: 'temporal_analysis',
          values: ['end_of_month'],
          weight: 1.0,
          cacheEnabled: true,
          parallelSafe: true,
        },
        detectionTimeMs: 1,
        cacheUsed: false,
        retryCount: 0,
      };

      const { session, result } = setupTest();
      result.emailId = mockEmail.id;
      executeAttributeInfluence(mockEmail, session, result, mockConfig);

      // Subtype role should take precedence
      const subtypeInfluence = result.attributeContext.influenceApplications.find(
        (app) => app.targetCategory === 'FINANCIAL.BILLING' && app.attributeUsed === 'end_of_month'
      );

      expect(subtypeInfluence).toEqual(
        expect.objectContaining({
          targetCategory: 'FINANCIAL.BILLING',
          attributeUsed: 'end_of_month',
          roleType: 'PRIMARY_BOOST', // Subtype role takes precedence
          scoreImpact: 15, // PRIMARY_BOOST bonus
        })
      );
    });
  });

  describe('Performance and Processing Metadata', () => {
    test('should track processing duration', () => {
      const { session, result } = setupTest();
      result.emailId = mockEmail.id;
      executeAttributeInfluence(mockEmail, session, result, mockConfig);

      expect(result.explainabilityTrace.stageTimings.attribute_influence).toBeGreaterThanOrEqual(0);
      expect(result.explainabilityTrace.stageTimings.attribute_influence).toBeLessThan(1000); // Should be fast
    });

    test('should track configuration references', () => {
      const { session, result } = setupTest();
      result.emailId = mockEmail.id;
      executeAttributeInfluence(mockEmail, session, result, mockConfig);

      expect(result.explainabilityTrace.configurationRefs.attribute_influence).toBe(
        'processing_config.attribute_relevance'
      );
    });

    test('should preserve existing context data', () => {
      const originalContext = { ...mockContext };

      const { session, result } = setupTest();
      result.emailId = mockEmail.id;
      executeAttributeInfluence(mockEmail, session, result, mockConfig);

      // Original context should be preserved
      expect(mockContext.emailId).toBe(originalContext.emailId);
      expect(mockContext.detectionMetadata).toEqual(originalContext.detectionMetadata);
      expect(result).toBeDefined();
    });
  });

  describe('Error Handling and Edge Cases', () => {
    test('should handle missing attribute relevance configuration', () => {
      // Create config without attribute relevance configuration
      const configWithoutAttributeRelevance = {
        ...mockConfig,
        processing_config: {
          ...mockConfig.processing_config,
        },
      };
      // Remove the property to simulate missing configuration
      delete (
        configWithoutAttributeRelevance.processing_config as Partial<
          typeof configWithoutAttributeRelevance.processing_config
        >
      ).attribute_relevance;

      const { session, result } = setupTest();
      result.emailId = mockEmail.id;

      expect(() => executeAttributeInfluence(mockEmail, session, result, configWithoutAttributeRelevance)).toThrow(
        'Attribute relevance configuration not found'
      );
    });

    test('should handle unknown attributes gracefully', () => {
      // Add unknown attribute to context
      mockContext.detectionMetadata.unknown_attribute = {
        detectedAt: new Date(),
        detectionMethod: 'derived',
        confidence: 0.5,
        parallelProcessed: false,
        dependencies: [],
        sourceField: 'body',
        matchedValue: 'unknown',
        detectorConfig: {
          field: 'body',
          operation: 'unknown',
          values: ['unknown'],
          weight: 1.0,
          cacheEnabled: true,
          parallelSafe: true,
        },
        detectionTimeMs: 1,
        cacheUsed: false,
        retryCount: 0,
      };

      const { session, result } = setupTest();
      result.emailId = mockEmail.id;
      executeAttributeInfluence(mockEmail, session, result, mockConfig);

      // Should not crash, unknown attributes ignored
      expect(result.attributeContext.influenceApplications).not.toContainEqual(
        expect.objectContaining({
          attributeUsed: 'unknown_attribute',
        })
      );
    });

    test('should handle empty detection metadata', () => {
      mockContext.detectionMetadata = {};

      const { session, result } = setupTest();
      result.emailId = mockEmail.id;
      executeAttributeInfluence(mockEmail, session, result, mockConfig);

      expect(result.attributeContext.influenceApplications).toHaveLength(0);
      expect(result.explainabilityTrace.stageTimings.attribute_influence).toBeGreaterThanOrEqual(0);
    });

    test('should validate role configurations', () => {
      // Invalid role in configuration
      if ('category_roles' in mockConfig.processing_config.attribute_relevance.FINANCIAL) {
        mockConfig.processing_config.attribute_relevance.FINANCIAL.category_roles.financial_domain =
          'INVALID_ROLE' as AttributeRole;
      }

      const { session, result } = setupTest();
      result.emailId = mockEmail.id;

      expect(() => executeAttributeInfluence(mockEmail, session, result, mockConfig)).toThrow(
        'Invalid attribute role: INVALID_ROLE'
      );
    });
  });

  describe('Integration with Previous Stages', () => {
    test('should work with attribute detection results', () => {
      // Simulate typical attribute detection output
      mockContext.detectionMetadata = {
        financial_domain: {
          detectedAt: new Date(),
          detectionMethod: 'domain_lookup',
          confidence: 0.95,
          parallelProcessed: false,
          dependencies: [],
          sourceField: 'from.address',
          matchedValue: 'financial.com',
          detectorConfig: {
            field: 'from.address',
            operation: 'domain_extract',
            values: ['financial.com'],
            weight: 1.0,
            cacheEnabled: true,
            parallelSafe: true,
          },
          detectionTimeMs: 5,
          cacheUsed: false,
          retryCount: 0,
        },
        invoice_pattern: {
          detectedAt: new Date(),
          detectionMethod: 'pattern',
          confidence: 0.88,
          parallelProcessed: false,
          dependencies: [],
          sourceField: 'body',
          matchedValue: 'invoice',
          detectorConfig: {
            field: 'body',
            operation: 'regex_pattern',
            values: ['invoice'],
            weight: 1.0,
            cacheEnabled: true,
            parallelSafe: true,
          },
          detectionTimeMs: 3,
          cacheUsed: false,
          retryCount: 0,
        },
        end_of_month: {
          detectedAt: new Date(),
          detectionMethod: 'derived',
          confidence: 0.72,
          parallelProcessed: false,
          dependencies: [],
          sourceField: 'date',
          matchedValue: 'end_of_month',
          detectorConfig: {
            field: 'date',
            operation: 'temporal_analysis',
            values: ['end_of_month'],
            weight: 1.0,
            cacheEnabled: true,
            parallelSafe: true,
          },
          detectionTimeMs: 1,
          cacheUsed: false,
          retryCount: 0,
        },
      };

      const { session, result } = setupTest();
      result.emailId = mockEmail.id;
      executeAttributeInfluence(mockEmail, session, result, mockConfig);

      // Should process all detected attributes with appropriate roles
      // 3 attributes but some attributes apply to both category and subtype levels
      expect(result.attributeContext.influenceApplications.length).toBeGreaterThan(0);

      const financialInfluences = result.attributeContext.influenceApplications.filter(
        (app) => app.targetCategory === 'FINANCIAL'
      );
      expect(financialInfluences.length).toBeGreaterThan(0); // Should have financial influences
    });

    test('should preserve stage chain data', () => {
      // Simulate data from previous stages
      const emailWithStageData = {
        ...mockEmail,
        stage_results: {
          hard_assertions: { completed: true },
          strong_indicators: { completed: true },
          rule_scoring: { completed: true },
          attribute_detection: { completed: true },
        },
      } as TestEmailMessage;

      const { session, result } = setupTest();
      result.emailId = emailWithStageData.id;
      executeAttributeInfluence(emailWithStageData, session, result, mockConfig);

      // Should have attribute influence execution tracked
      expect(result.explainabilityTrace.configurationRefs.attribute_influence).toBeDefined();
      expect(result.explainabilityTrace.stageTimings.attribute_influence).toBeGreaterThanOrEqual(0);
      expect(result).toBeDefined();
    });
  });
});

