const AttributeRelevanceMatrixSchema = z
  .object({
    _roles_legend: z.object({
      CORE: z.string(),
      PRIMARY_BOOST: z.string(),
      SECONDARY_BOOST: z.string(),
      DISAMBIGUATOR: z.string(),
      FILTER: z.string(),
      STRUCTURAL: z.string(),
      DERIVED_LINK: z.string(),
      NEUTRAL: z.string(),
    }),
  })
  .catchall(
    z.object({
      category_roles: z.record(z.string(), AttributeRoleSchema),
      subtypes: z
        .record(
          z.string(),
          z.object({
            roles: z.record(z.string(), AttributeRoleSchema),
          })
        )
        .optional(),
      tuning_parameters: z
        .object({
          bonus_multipliers: z.record(z.string(), z.number().min(0).default(1.0)),
          penalty_multipliers: z.record(z.string(), z.number().min(0).default(1.0)),
          max_influence: z.number().min(0).default(0.5),
        })
        .optional(),
    })
  );

// AI prompt system schema
const AIPromptSystemSchema = z.object({
  feature_extraction: z.object({
    system_prompt: z.array(z.string()),
    user_prompt: z.array(z.string()),
    temperature: z.number().min(0).max(2).default(0.1),
    max_tokens: z.number().int().min(100).default(1000),
  }),
  final_classification: z.object({
    system_prompt: z.array(z.string()),
    user_prompt: z.array(z.string()),
    temperature: z.number().min(0).max(2).default(0.1),
    max_tokens: z.number().int().min(50).default(500),
  }),
  model_settings: z
    .object({
      model_name: z.string().default('gpt-4'),
      fallback_model: z.string().default('gpt-3.5-turbo'),
      request_timeout_ms: z.number().int().min(1000).default(30000),
      retry_attempts: z.number().int().min(0).default(3),
    })
    .optional(),
});

// JSON Schema validation (for feature extraction schema)
const JSONSchemaSchema = z.object({
  type: z.string(),
  properties: z.record(z.string(), z.any()),
  required: z.array(z.string()),
  additionalProperties: z.boolean().default(false),
  $schema: z.string().optional(),
  title: z.string().optional(),
  description: z.string().optional(),
});

// Main processing config schema
const ProcessingConfigSchema = z.object({
  version: z.number().int().min(1),
  taxonomy_notes: z.string(),
  settings: ProcessingSettingsSchema,
  category_signals: z.record(z.string(), CategorySignalsSchema),
  confidence_thresholds: ConfidenceThresholdsSchema,
  multi_label_policy: MultiLabelPolicySchema,
  domain_signal_overrides: DomainOverridesSchema,
  domain_signal_resolution: DomainResolutionSchema,
  top_level_categories: z.record(z.string(), TopLevelCategorySchema),
  attributes: AttributeSystemSchema,
  attribute_relevance: AttributeRelevanceMatrixSchema,
  ai_prompts: AIPromptSystemSchema,
  feature_extraction_schema: JSONSchemaSchema,
});

// Main category configuration schema
export const CategoryConfigurationSchema = z.object({
  version: z.string().regex(/^\d+\.\d+\.\d+$/, 'Must be semantic version format (x.y.z)'),
  lastModified: z.coerce.date(),
  hash: z.string().length(64, 'Must be SHA-256 hash'),

  // Main processing configuration
  processing_config: ProcessingConfigSchema,

  // Validation metadata
  schemaVersion: z.string().default('1.0.0'),
  validationPassed: z.boolean(),
  validationErrors: z.array(z.string()).default([]),

