    it('should handle large candidate score sets efficiently', () => {
      const largeCandidateScores: Record<string, CandidateScore> = {};
      for (let i = 0; i < 100; i++) {
        largeCandidateScores[`category_${i}`] = {
          score: Math.random() * 10,
          confidence: Math.random() * 10,
          decision: 'candidate',
        };
      }

      const classification: AIRoutingClassificationInput = {
        gmailId: 'test-123',
        sessionId: 'session-123',
        selectedLabels: [
          {
            category: 'financial',
            confidence: 12.0,
            isPrimary: true,
            subtype: 'receipt',
            selectionRationale: 'Large dataset test',
          },
        ],
        candidateScores: largeCandidateScores,
      };

      const startTime = Date.now();
      const result = aiRoutingStage(mockEmail, mockSession, classification, mockConfig);
      const endTime = Date.now();

      expect(endTime - startTime).toBeLessThan(100);
      expect(result.routing_decision).toBeDefined();
    });
  });
});

