/**
 * Unit Tests for AI Routing Stage
 *
 * Following TDD approach - these tests MUST FAIL before implementation.
 * This stage determines whether emails need AI classification based on confidence scores.
 */

import { aiRoutingStage, AIRoutingClassificationInput } from '../../src/stages/ai-routing';
import { CandidateScore } from '../../src/types/classification-result';
import { EmailMessage, ClassificationSession } from '../../src/types';

describe('AI Routing Stage', () => {
  const mockConfig = {
    settings: {
      ai_routing: {
        high_confidence_threshold: 15,
        ai_required_threshold: 12,
        skip_ai_conditions: ['hard_assertion'],
      },
    },
    confidenceThresholds: {
      highConfidence: 15,
      mediumConfidence: 8,
      lowConfidence: 3,
      secondaryLabelMinGap: 5,
      aiClassificationRequired: 12,
    },
  };

  const mockEmail: EmailMessage = {
    id: 'test-123',
    threadId: 'thread-123',
    gmailLabels: [],
    payload: {
      mimeType: 'text/plain',
      headers: [
        { name: 'Subject', value: 'Test email' },
        { name: 'From', value: 'Test User <test@example.com>' },
        { name: 'To', value: 'User <user@example.com>' },
      ],
    },
    subject: 'Test email',
    from: { email: 'test@example.com', name: 'Test User', raw: 'Test User <test@example.com>' },
    to: [{ email: 'user@example.com', name: 'User', raw: 'User <user@example.com>' }],
    bodyPlain: 'Test email body',
    bodyHtml: '<p>Test email body</p>',
    date: new Date('2024-01-01T10:00:00Z'),
    isProcessed: false,
    processingPriority: 1,
  };

  const mockSession: ClassificationSession = {
    id: 'session-123',
    startedAt: new Date('2024-01-01T10:00:00Z'),
    emailCount: 1,
    successCount: 0,
    errorCount: 0,
    processingMode: 'parallel',
    batchSize: 1,
    performanceMetrics: {
      totalDurationMs: 0,
      avgEmailDurationMs: 0,
      parallelStagesCount: 0,
      databaseBatchOps: 0,
    },
    configVersion: 'test-version',
    configSnapshot: {},
    errors: [],
    warnings: [],
  };

  describe('High Confidence Routing', () => {
    it('should skip AI for high confidence primary labels (>=15)', () => {
      const highConfidenceClassification: AIRoutingClassificationInput = {
        gmailId: 'test-123',
        sessionId: 'session-123',
        selectedLabels: [
          {
            category: 'financial',
            confidence: 16.5,
            score: 16.5,
            isPrimary: true,
            labelOrder: 1,
            subtype: 'statement',
            selectionRationale: 'High confidence financial classification',
          },
        ],
        candidateScores: {
          financial: { score: 16.5, confidence: 16.5, decision: 'selected' },
        },
      };

      const result = aiRoutingStage(mockEmail, mockSession, highConfidenceClassification, mockConfig);

      expect(result.routing_decision.route_to_ai).toBe(false);
      expect(result.routing_decision.routing_reason).toContain('High confidence');
      expect(result.routing_decision.routing_reason).toContain('financial');
      expect(result.routing_decision.routing_reason).toContain('16.5');
      expect(result.routing_decision.confidence_assessment).toBe('high_confidence');
      expect(result.routing_decision.cost_consideration).toBe('ai_unnecessary');
      expect(result.routing_branch).toBe('direct_to_merge');
    });

    it('should skip AI when hard assertion condition is met', () => {
      const hardAssertionClassification: AIRoutingClassificationInput = {
        gmailId: 'test-123',
        sessionId: 'session-123',
        selectedLabels: [
          {
            category: 'financial',
            confidence: 12.0,
            score: 12.0,
            isPrimary: true,
            labelOrder: 1,
            subtype: 'statement',
            selectionRationale: 'Hard assertion based on domain match',
          },
        ],
        candidateScores: {
          financial: { score: 12.0, confidence: 12.0, decision: 'selected', hardAssertion: true },
        },
      };

      const result = aiRoutingStage(mockEmail, mockSession, hardAssertionClassification, mockConfig);

      expect(result.routing_decision.route_to_ai).toBe(false);
      expect(result.routing_decision.routing_reason).toContain('hard assertion');
      expect(result.routing_decision.confidence_assessment).toBe('hard_assertion_skip');
      expect(result.routing_branch).toBe('direct_to_merge');
    });
  });

  describe('Medium Confidence Routing', () => {
    it('should route to AI for medium confidence scores (8-14)', () => {
      const mediumConfidenceClassification: AIRoutingClassificationInput = {
        gmailId: 'test-123',
        sessionId: 'session-123',
        selectedLabels: [
          {
            category: 'actionable',
            confidence: 10.5,
            score: 10.5,
            isPrimary: true,
            labelOrder: 1,
            subtype: 'implicit_action',
            selectionRationale: 'Medium confidence actionable classification',
          },
        ],
        candidateScores: {
          actionable: { score: 10.5, confidence: 10.5, decision: 'selected' },
          personal: { score: 8.2, confidence: 8.2, decision: 'candidate' },
        },
      };

      const result = aiRoutingStage(mockEmail, mockSession, mediumConfidenceClassification, mockConfig);

      expect(result.routing_decision.route_to_ai).toBe(true);
      expect(result.routing_decision.routing_reason).toContain('Medium confidence');
      expect(result.routing_decision.routing_reason).toContain('actionable');
      expect(result.routing_decision.routing_reason).toContain('10.5');
      expect(result.routing_decision.confidence_assessment).toBe('medium_confidence');
      expect(result.routing_decision.cost_consideration).toBe('disambiguation_valuable');
      expect(result.routing_branch).toBe('ai_classification');
    });

    it('should route to AI when multiple labels are selected', () => {
      const multiLabelClassification: AIRoutingClassificationInput = {
        gmailId: 'test-123',
        sessionId: 'session-123',
        selectedLabels: [
          {
            category: 'financial',
            confidence: 12.0,
            score: 12.0,
            isPrimary: true,
            labelOrder: 1,
            subtype: 'receipt',
            selectionRationale: 'Primary financial classification',
          },
          {
            category: 'actionable',
            confidence: 9.5,
            score: 9.5,
            isPrimary: false,
            labelOrder: 2,
            subtype: 'implicit_action',
            selectionRationale: 'Secondary actionable classification',
          },
        ],
        candidateScores: {
          financial: { score: 12.0, confidence: 12.0, decision: 'selected' },
          actionable: { score: 9.5, confidence: 9.5, decision: 'selected' },
        },
      };

      const result = aiRoutingStage(mockEmail, mockSession, multiLabelClassification, mockConfig);

      expect(result.routing_decision.route_to_ai).toBe(true);
      expect(result.routing_decision.routing_reason).toContain('multiple labels');
      expect(result.routing_decision.cost_consideration).toBe('multi_label_validation');
      expect(result.routing_branch).toBe('ai_classification');
    });

    it('should route to AI when close competitors exist', () => {
      const closeCompetitorsClassification: AIRoutingClassificationInput = {
        gmailId: 'test-123',
        sessionId: 'session-123',
        selectedLabels: [
          {
            category: 'commerce_logistics',
            confidence: 11.0,
            score: 11.0,
            isPrimary: true,
            labelOrder: 1,
            subtype: 'shipping_update',
            selectionRationale: 'Close competition with travel category',
          },
        ],
        candidateScores: {
          commerce_logistics: { score: 11.0, confidence: 11.0, decision: 'selected' },
          travel: { score: 9.5, confidence: 9.5, decision: 'candidate' },
          personal: { score: 8.8, confidence: 8.8, decision: 'candidate' },
        },
      };

      const result = aiRoutingStage(mockEmail, mockSession, closeCompetitorsClassification, mockConfig);

      expect(result.routing_decision.route_to_ai).toBe(true);
      expect(result.routing_decision.routing_reason).toContain('close competing categories');
      expect(result.routing_decision.cost_consideration).toBe('disambiguation_valuable');
      expect(result.routing_branch).toBe('ai_classification');
    });
  });

  describe('Low Confidence Routing', () => {
    it('should skip AI for very low confidence scores (<3)', () => {
      const lowConfidenceClassification: AIRoutingClassificationInput = {
        gmailId: 'test-123',
        sessionId: 'session-123',
        selectedLabels: [
          {
            category: 'uncategorized',
            confidence: 2.1,
            isPrimary: true,
            subtype: 'needs_review',
            selectionRationale: 'Very low confidence classification',
          },
        ],
        candidateScores: {
          uncategorized: { score: 2.1, confidence: 2.1, decision: 'selected' },
        },
      };

      const result = aiRoutingStage(mockEmail, mockSession, lowConfidenceClassification, mockConfig);

      expect(result.routing_decision.route_to_ai).toBe(false);
      expect(result.routing_decision.routing_reason).toContain('Very low confidence');
      expect(result.routing_decision.routing_reason).toContain('likely unclassifiable');
      expect(result.routing_decision.confidence_assessment).toBe('very_low_confidence');
      expect(result.routing_decision.cost_consideration).toBe('ai_ineffective');
      expect(result.routing_branch).toBe('direct_to_merge');
    });

    it('should skip AI for scores below AI routing threshold but above low threshold', () => {
      const belowThresholdClassification: AIRoutingClassificationInput = {
        gmailId: 'test-123',
        sessionId: 'session-123',
        selectedLabels: [
          {
            category: 'system_notifications',
            confidence: 6.5,
            isPrimary: true,
            subtype: 'service_status',
            selectionRationale: 'Below AI routing threshold',
          },
        ],
        candidateScores: {
          system_notifications: { score: 6.5, confidence: 6.5, decision: 'selected' },
        },
      };

      const result = aiRoutingStage(mockEmail, mockSession, belowThresholdClassification, mockConfig);

      expect(result.routing_decision.route_to_ai).toBe(false);
      expect(result.routing_decision.routing_reason).toContain('below AI routing threshold');
      expect(result.routing_decision.confidence_assessment).toBe('low_medium_confidence');
      expect(result.routing_decision.cost_consideration).toBe('cost_threshold_not_met');
      expect(result.routing_branch).toBe('direct_to_merge');
    });
  });

  describe('No Labels Selected', () => {
    it('should route to AI when no labels are selected', () => {
      const noLabelsClassification: AIRoutingClassificationInput = {
        gmailId: 'test-123',
        sessionId: 'session-123',
        selectedLabels: [],
        candidateScores: {},
      };

      const result = aiRoutingStage(mockEmail, mockSession, noLabelsClassification, mockConfig);

      expect(result.routing_decision.route_to_ai).toBe(true);
      expect(result.routing_decision.routing_reason).toContain('No labels selected');
      expect(result.routing_decision.routing_reason).toContain('AI classification may recover');
      expect(result.routing_decision.confidence_assessment).toBe('no_classification');
      expect(result.routing_decision.cost_consideration).toBe('recovery_attempt');
      expect(result.routing_branch).toBe('ai_classification');
    });
  });

  describe('Edge Cases and Error Handling', () => {
    it('should handle missing primary label gracefully', () => {
      const noPrimaryClassification: AIRoutingClassificationInput = {
        gmailId: 'test-123',
        sessionId: 'session-123',
        selectedLabels: [
          {
            category: 'financial',
            confidence: 10.0,
            isPrimary: false,
            subtype: 'receipt',
            selectionRationale: 'No primary flag set',
          },
        ],
        candidateScores: {
          financial: { score: 10.0, confidence: 10.0, decision: 'selected' },
        },
      };

      const result = aiRoutingStage(mockEmail, mockSession, noPrimaryClassification, mockConfig);

      // Should use first label as primary when no primary flag is set
      expect(result.routing_decision.route_to_ai).toBe(true);
      expect(result.routing_decision.routing_reason).toContain('Medium confidence');
      expect(result.routing_decision.routing_reason).toContain('financial');
    });

    it('should handle malformed classification input', () => {
      const malformedClassification: AIRoutingClassificationInput = {
        gmailId: 'test-123',
        sessionId: 'session-123',
        selectedLabels: [
          {
            category: 'financial',
            confidence: NaN,
            isPrimary: true,
            subtype: 'receipt',
            selectionRationale: 'Invalid confidence score',
          },
        ],
        candidateScores: {},
      };

      expect(() => {
        aiRoutingStage(mockEmail, mockSession, malformedClassification, mockConfig);
      }).toThrow('Invalid confidence score');
    });

    it('should handle custom confidence thresholds', () => {
      const customConfig = {
        ...mockConfig,
        settings: {
          ai_routing: {
            high_confidence_threshold: 20,
            ai_required_threshold: 10,
            skip_ai_conditions: [],
          },
        },
      };

      const customClassification: AIRoutingClassificationInput = {
        gmailId: 'test-123',
        sessionId: 'session-123',
        selectedLabels: [
          {
            category: 'financial',
            confidence: 18.0,
            isPrimary: true,
            subtype: 'statement',
            selectionRationale: 'High confidence with custom thresholds',
          },
        ],
        candidateScores: {
          financial: { score: 18.0, confidence: 18.0, decision: 'selected' },
        },
      };

      const result = aiRoutingStage(mockEmail, mockSession, customClassification, customConfig);

      // With higher threshold (20), score of 18 should route to AI
      expect(result.routing_decision.route_to_ai).toBe(true);
      expect(result.routing_decision.confidence_assessment).toBe('medium_confidence');
    });
  });

  describe('Close Competitors Analysis', () => {
    it('should correctly identify close competitors within gap threshold', () => {
      const competitiveClassification: AIRoutingClassificationInput = {
        gmailId: 'test-123',
        sessionId: 'session-123',
        selectedLabels: [
          {
            category: 'travel',
            confidence: 12.0,
            isPrimary: true,
            subtype: 'flight_alert',
            selectionRationale: 'Travel with commerce logistics competition',
          },
        ],
        candidateScores: {
          travel: { score: 12.0, confidence: 12.0, decision: 'selected' },
          commerce_logistics: { score: 10.5, confidence: 10.5, decision: 'candidate' },
          personal: { score: 9.8, confidence: 9.8, decision: 'candidate' },
          financial: { score: 4.0, confidence: 4.0, decision: 'rejected' },
        },
      };

      const result = aiRoutingStage(mockEmail, mockSession, competitiveClassification, mockConfig);

      expect(result.routing_decision.route_to_ai).toBe(true);
      expect(result.routing_decision.routing_reason).toContain('close competing categories');
      expect(result.routing_decision.cost_consideration).toBe('disambiguation_valuable');
    });

    it('should not consider distant competitors as close', () => {
      const nonCompetitiveClassification: AIRoutingClassificationInput = {
        gmailId: 'test-123',
        sessionId: 'session-123',
        selectedLabels: [
          {
            category: 'financial',
            confidence: 14.0,
            isPrimary: true,
            subtype: 'statement',
            selectionRationale: 'Clear financial with distant competitors',
          },
        ],
        candidateScores: {
          financial: { score: 14.0, confidence: 14.0, decision: 'selected' },
          actionable: { score: 8.0, confidence: 8.0, decision: 'candidate' },
