    id: 'session-123',
    startedAt: new Date('2024-01-01T10:00:00Z'),
    emailCount: 1,
    successCount: 0,
    errorCount: 0,
    processingMode: 'parallel',
    batchSize: 1,
    performanceMetrics: {
      totalDurationMs: 0,
      avgEmailDurationMs: 0,
      parallelStagesCount: 0,
      databaseBatchOps: 0,
    },
    configVersion: 'test-version',
    configSnapshot: {},
    errors: [],
    warnings: [],
  };

